import{_ as t,c as a,o,ae as i}from"./chunks/framework.CDjunVez.js";const h=JSON.parse('{"title":"Creating a Website","description":"","frontmatter":{},"headers":[],"relativePath":"website/create.md","filePath":"website/create.md"}'),s={name:"website/create.md"};function n(r,e,l,c,d,p){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="creating-a-website" tabindex="-1">Creating a Website <a class="header-anchor" href="#creating-a-website" aria-label="Permalink to &quot;Creating a Website&quot;">​</a></h1><p>KiwiPanel makes it easy to create and provision websites. The creation process follows a simple 3-step flow: <strong>fill in the form → review → confirm</strong>. Everything else — Linux user, directories, web server config, and optional database — is set up automatically.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><ol><li>Navigate to <strong>Websites</strong> in the sidebar</li><li>Click the <strong>Create Website</strong> button</li><li>Fill in the form and click <strong>Create Website</strong></li><li>Review the configuration summary</li><li>Click <strong>Confirm &amp; Create</strong> to provision the website</li></ol><p>The entire process takes just a few seconds.</p><h2 id="step-1-fill-in-the-form" tabindex="-1">Step 1: Fill in the Form <a class="header-anchor" href="#step-1-fill-in-the-form" aria-label="Permalink to &quot;Step 1: Fill in the Form&quot;">​</a></h2><h3 id="owner" tabindex="-1">Owner <a class="header-anchor" href="#owner" aria-label="Permalink to &quot;Owner&quot;">​</a></h3><p>Choose who owns this website:</p><ul><li><strong>Admin users</strong> can select any existing user from the dropdown, or create a new client on the fly</li><li><strong>Client users</strong> are automatically assigned as the owner (no dropdown shown)</li></ul><div class="tip custom-block"><p class="custom-block-title">Create a client on the fly</p><p>Select <strong>&quot;✨ + Create new client&quot;</strong> from the owner dropdown. KiwiPanel will auto-generate a username and strong password. The credentials are shown <strong>once</strong> on the success page — make sure to copy them before leaving.</p></div><h3 id="primary-domain" tabindex="-1">Primary Domain <a class="header-anchor" href="#primary-domain" aria-label="Permalink to &quot;Primary Domain&quot;">​</a></h3><p>Enter the main domain for this website (e.g., <code>example.com</code>). Do <strong>not</strong> include <code>http://</code> or <code>www</code>.</p><p>This domain becomes:</p><ul><li>The website&#39;s identity in the panel</li><li>The primary domain in the web server configuration</li><li>The basis for auto-generated directory names and database names</li></ul><h3 id="domain-aliases-optional" tabindex="-1">Domain Aliases (Optional) <a class="header-anchor" href="#domain-aliases-optional" aria-label="Permalink to &quot;Domain Aliases (Optional)&quot;">​</a></h3><p>Add additional domains that should also point to this website. Common use cases:</p><ul><li><code>www.example.com</code> alongside <code>example.com</code></li><li>A staging domain like <code>staging.example.com</code></li><li>An old domain that should serve the same content</li></ul><p>Click <strong>Add Domain Alias</strong> to add more, or click the ✕ button to remove one.</p><h3 id="website-type" tabindex="-1">Website Type <a class="header-anchor" href="#website-type" aria-label="Permalink to &quot;Website Type&quot;">​</a></h3><p>Choose one of the three supported website types:</p><table tabindex="0"><thead><tr><th>Type</th><th>Best for</th><th>What it does</th></tr></thead><tbody><tr><td><strong>PHP Application</strong></td><td>WordPress, Laravel, custom PHP apps</td><td>Sets up PHP-FPM with your chosen PHP version</td></tr><tr><td><strong>Reverse Proxy</strong></td><td>Node.js, Python, Go, or any backend app</td><td>Forwards traffic to your backend application</td></tr><tr><td><strong>Static Site</strong></td><td>HTML/CSS/JS, JAMstack, documentation</td><td>Serves static files only — no server-side processing</td></tr></tbody></table><h4 id="php-application-options" tabindex="-1">PHP Application Options <a class="header-anchor" href="#php-application-options" aria-label="Permalink to &quot;PHP Application Options&quot;">​</a></h4><p>When you select <strong>PHP Application</strong>, you can configure:</p><ul><li><strong>PHP Version</strong> — Choose from the installed PHP versions on your server (e.g., 8.1, 8.2, 8.3). The default version is pre-selected.</li><li><strong>Memory Limit</strong> — Maximum memory per PHP process (default: 256M)</li><li><strong>Max Execution Time</strong> — Maximum script runtime in seconds (default: 300)</li><li><strong>Upload Max Size</strong> — Maximum file upload size (default: 64 MB)</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can change all PHP settings later from the website&#39;s settings page. These are just the initial values.</p></div><h4 id="reverse-proxy-options" tabindex="-1">Reverse Proxy Options <a class="header-anchor" href="#reverse-proxy-options" aria-label="Permalink to &quot;Reverse Proxy Options&quot;">​</a></h4><p>When you select <strong>Reverse Proxy</strong>, configure:</p><ul><li><strong>Backend URL</strong> — The address of your backend application (e.g., <code>127.0.0.1:3000</code> or <code>localhost:8080</code>)</li><li><strong>Backend Protocol</strong> — HTTP or HTTPS, depending on what your backend expects</li><li><strong>WebSocket Support</strong> — Enable if your app uses WebSockets (e.g., real-time chat, live updates)</li><li><strong>Preserve Host Header</strong> — Forward the original host header to your backend</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Make sure your backend application is already running and accessible at the specified address before creating the website.</p></div><h4 id="static-site-options" tabindex="-1">Static Site Options <a class="header-anchor" href="#static-site-options" aria-label="Permalink to &quot;Static Site Options&quot;">​</a></h4><p>When you select <strong>Static Site</strong>, you can optionally configure:</p><ul><li><strong>Document Root Subdirectory</strong> — Where your static files live within the website directory (default: <code>public_html</code>)</li><li><strong>Index Files</strong> — Default index files to serve (default: <code>index.html, index.htm</code>)</li></ul><h3 id="database-optional" tabindex="-1">Database (Optional) <a class="header-anchor" href="#database-optional" aria-label="Permalink to &quot;Database (Optional)&quot;">​</a></h3><p>Toggle <strong>Create a database</strong> to provision a MariaDB database along with the website:</p><ul><li><strong>Database Name</strong> — Auto-generated from the domain (e.g., <code>example_com_db</code>), or enter a custom name</li><li><strong>Database User</strong> — Auto-generated from the domain (e.g., <code>example_com_usr</code>), or enter a custom name</li><li><strong>Password</strong> — Always auto-generated securely (shown once on the success page)</li></ul><p>The database uses <code>utf8mb4</code> encoding by default.</p><h2 id="step-2-review-configuration" tabindex="-1">Step 2: Review Configuration <a class="header-anchor" href="#step-2-review-configuration" aria-label="Permalink to &quot;Step 2: Review Configuration&quot;">​</a></h2><p>After submitting the form, you&#39;ll see a <strong>review page</strong> summarizing everything:</p><ul><li>Website name, owner, and server</li><li>Website type and configuration details</li><li>Primary domain and any aliases</li><li>Directory structure preview (Linux user, document root)</li><li>Database settings (if enabled)</li></ul><p>This is your chance to double-check everything before provisioning.</p><div class="info custom-block"><p class="custom-block-title">Directory Structure</p><p>KiwiPanel automatically creates an isolated Linux user for each website. The directory structure looks like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home/{owner}/</span></span>
<span class="line"><span>  └── {linux_user}/</span></span>
<span class="line"><span>      ├── public_html/    ← Document root (your website files go here)</span></span>
<span class="line"><span>      ├── logs/           ← Access and error logs</span></span>
<span class="line"><span>      └── tmp/            ← Temporary files</span></span></code></pre></div></div><h2 id="step-3-confirm-create" tabindex="-1">Step 3: Confirm &amp; Create <a class="header-anchor" href="#step-3-confirm-create" aria-label="Permalink to &quot;Step 3: Confirm &amp; Create&quot;">​</a></h2><p>Click <strong>Confirm &amp; Create</strong> to start provisioning. KiwiPanel runs these steps automatically:</p><ol><li><strong>Creating website record</strong> — Saves the website to the database</li><li><strong>Setting up Linux user</strong> — Creates an isolated system user</li><li><strong>Provisioning directories</strong> — Creates the document root and supporting directories</li><li><strong>Configuring web server</strong> — Generates and applies the OpenLiteSpeed configuration</li><li><strong>Creating database</strong> — Provisions the MariaDB database (if enabled)</li></ol><p>You can watch the progress in real-time on the success page.</p><h2 id="after-creation" tabindex="-1">After Creation <a class="header-anchor" href="#after-creation" aria-label="Permalink to &quot;After Creation&quot;">​</a></h2><p>Once the website is created, you&#39;ll see:</p><ul><li><strong>Website information</strong> — Domain, owner, Linux user, and document root</li><li><strong>Generated credentials</strong> (if applicable) — Client account username/password and database credentials</li></ul><div class="warning custom-block"><p class="custom-block-title">Save your credentials!</p><p>If you created a new client or a database, the generated passwords are shown <strong>only once</strong>. Copy them before leaving the page — they cannot be retrieved later.</p></div><h3 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h3><p>After creating your website, you can:</p><ul><li><strong>Upload files</strong> via SFTP using the Linux user credentials, or use the built-in File Manager</li><li><strong>Point your DNS</strong> — Create an A record pointing your domain to your server&#39;s IP address</li><li><strong>Install SSL</strong> — Set up a free Let&#39;s Encrypt certificate for HTTPS</li><li><strong>Install an app</strong> — Deploy WordPress or other applications</li><li><strong>Manage settings</strong> — Adjust PHP version, memory limits, or web server configuration</li></ul><h2 id="deleting-a-website" tabindex="-1">Deleting a Website <a class="header-anchor" href="#deleting-a-website" aria-label="Permalink to &quot;Deleting a Website&quot;">​</a></h2><p>To delete a website:</p><ol><li>Go to <strong>Websites</strong> and find the website you want to remove</li><li>Click on the website to open its detail page</li><li>Click the <strong>Delete</strong> button and confirm</li></ol><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>Deleting a website permanently removes:</p><ul><li>The website record and domain configuration</li><li>The Linux user and all website files on disk</li><li>The web server configuration</li><li>PHP-FPM pool configuration (for PHP sites)</li></ul><p>This action <strong>cannot be undone</strong>. Make sure to back up any files you need before deleting.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="domain-not-resolving" tabindex="-1">Domain not resolving <a class="header-anchor" href="#domain-not-resolving" aria-label="Permalink to &quot;Domain not resolving&quot;">​</a></h3><p>Make sure your DNS A record points to your server&#39;s IP address. DNS changes can take up to 24–48 hours to propagate, though it&#39;s usually much faster.</p><h3 id="_502-bad-gateway-on-reverse-proxy-sites" tabindex="-1">&quot;502 Bad Gateway&quot; on reverse proxy sites <a class="header-anchor" href="#_502-bad-gateway-on-reverse-proxy-sites" aria-label="Permalink to &quot;&quot;502 Bad Gateway&quot; on reverse proxy sites&quot;">​</a></h3><p>Your backend application is not running or not accessible at the configured address. Check that:</p><ul><li>Your application is started and listening on the correct port</li><li>The backend URL in the website settings matches your application&#39;s address</li><li>No firewall rules are blocking the connection</li></ul><h3 id="website-shows-default-page-instead-of-your-content" tabindex="-1">Website shows default page instead of your content <a class="header-anchor" href="#website-shows-default-page-instead-of-your-content" aria-label="Permalink to &quot;Website shows default page instead of your content&quot;">​</a></h3><p>Upload your files to the <strong>document root</strong> directory shown on the website detail page (usually <code>public_html/</code>). Make sure your main page is named <code>index.html</code> or <code>index.php</code>.</p>`,64)])])}const g=t(s,[["render",n]]);export{h as __pageData,g as default};
